  1	import * as React from 'react';
  2	import { EllipsisVIcon } from '@patternfly/react-icons';
  3	import {
  4	  Dropdown,
  5	  DropdownItem,
  6	  DropdownList,
  7	  MenuToggle,
  8	  MenuToggleElement,
  9	  Button,
 10	  ButtonVariant,
 11	  Tooltip,
 12	} from '@patternfly/react-core';
 13	import { Modal, ModalBody, ModalFooter, ModalHeader } from '@patternfly/react-core/next';
 14	import { k8sDelete, K8sResourceCommon } from '@openshift-console/dynamic-plugin-sdk';
 15	import { useHistory } from 'react-router-dom';
 16	import resourceGVKMapping from '../utils/latest';
 17	import useAccessReviews from '../utils/resourceRBAC';
 18	import { getModelFromResource } from '../utils/getModelFromResource';
 19	type DropdownWithKebabProps = {
 20	  obj: K8sResourceCommon;
 21	};
 22	
 23	const DropdownWithKebab: React.FC<DropdownWithKebabProps> = ({ obj }) => {
 24	  const [isOpen, setIsOpen] = React.useState(false);
 25	  const [isDeleteModalOpen, setIsDeleteModalOpen] = React.useState(false);
 26	  const history = useHistory();
 27	  const model = getModelFromResource(obj);
 28	
 29	  const onToggleClick = () => {
 30	    setIsOpen(!isOpen);
 31	  };
 32	
 33	  const onDeleteConfirm = async () => {
 34	    try {
 35	      await k8sDelete({ model, resource: obj });
 36	      console.log('Successfully deleted', obj.metadata.name);
 37	    } catch (error) {
 38	      console.error('Failed to delete', obj.metadata.name, error);
 39	    } finally {
 40	      setIsDeleteModalOpen(false);
 41	    }
 42	  };
 43	
 44	  const policyType = obj.kind.toLowerCase();
 45	
 46	  const resourceGVK: { group: string; kind: string }[] = [
 47	    { group: resourceGVKMapping[obj.kind].group, kind: obj.kind },
 48	  ];
 49	  const { userRBAC } = useAccessReviews(resourceGVK);
 50	  const resourceRBAC = [
 51	    'TLSPolicy',
 52	    'DNSPolicy',
 53	    'RateLimitPolicy',
 54	    'AuthPolicy',
 55	    'Gateway',
 56	    'HTTPRoute',
 57	  ].reduce(
 58	    (acc, resource) => ({
 59	      ...acc,
 60	      [resource]: {
 61	        delete: userRBAC[`${resource}-delete`],
 62	        edit: userRBAC[`${resource}-update`],
 63	      },
 64	    }),
 65	    {} as Record<string, { delete: boolean }>,
 66	  );
 67	
 68	  const onEditClick = () => {
 69	    if (
 70	      obj.kind === 'AuthPolicy' ||
 71	      obj.kind === 'RateLimitPolicy' ||
 72	      obj.kind === 'Gateway' ||
 73	      obj.kind === 'HTTPRoute'
 74	    ) {
 75	      history.push({
 76	        pathname: `/k8s/ns/${obj.metadata.namespace}/${obj.apiVersion.replace('/', '~')}~${
 77	          obj.kind
 78	        }/${obj.metadata.name}/yaml`,
 79	      });
 80	    } else {
 81	      history.push({
 82	        pathname: `/k8s/ns/${obj.metadata.namespace}/${policyType}/name/${obj.metadata.name}/edit`,
 83	      });
 84	    }
 85	  };
 86	
 87	  const onDeleteClick = () => {
 88	    setIsDeleteModalOpen(true);
 89	  };
 90	
 91	  const onSelect = (
 92	    _event: React.MouseEvent<Element, MouseEvent> | undefined,
 93	    value: string | number | undefined,
 94	  ) => {
 95	    setIsOpen(false);
 96	    if (value === 'delete') {
 97	      onDeleteClick();
 98	    }
 99	  };
100	
101	  return (
102	    <>
103	      <Dropdown
104	        isOpen={isOpen}
105	        onSelect={onSelect}
106	        onOpenChange={(isOpen: boolean) => setIsOpen(isOpen)}
107	        toggle={(toggleRef: React.Ref<MenuToggleElement>) => (
108	          <MenuToggle
109	            ref={toggleRef}
110	            aria-label="kebab dropdown toggle"
111	            variant="plain"
112	            onClick={onToggleClick}
113	            isExpanded={isOpen}
114	          >
115	            <EllipsisVIcon />
116	          </MenuToggle>
117	        )}
118	        shouldFocusToggleOnSelect
119	      >
120	        <DropdownList>
121	          {resourceRBAC[obj.kind]['edit'] == true ? (
122	            <DropdownItem value="edit" key="edit" onClick={onEditClick}>
123	              Edit
124	            </DropdownItem>
125	          ) : (
126	            <Tooltip content={`You do not have permission to edit the ${obj.kind}`}>
127	              <DropdownItem
128	                value="edit"
129	                key="edit"
130	                onClick={onEditClick}
131	                isAriaDisabled={!resourceRBAC[obj.kind]['edit']}
132	              >
133	                Edit
134	              </DropdownItem>
135	            </Tooltip>
136	          )}
137	          {resourceRBAC[obj.kind]['delete'] == true ? (
138	            <DropdownItem value="delete" key="delete">
139	              Delete
140	            </DropdownItem>
141	          ) : (
142	            <Tooltip content={`You do not have permission to delete the ${obj.kind}`}>
143	              <DropdownItem
144	                value="delete"
145	                key="delete"
146	                isAriaDisabled={!resourceRBAC[obj.kind]['delete']}
147	              >
148	                Delete
149	              </DropdownItem>
150	            </Tooltip>
151	          )}
152	        </DropdownList>
153	      </Dropdown>
154	      <Modal
155	        isOpen={isDeleteModalOpen}
156	        onClose={() => setIsDeleteModalOpen(false)}
157	        aria-labelledby="delete-modal-title"
158	        aria-describedby="delete-modal-body"
159	        variant="medium"
160	      >
161	        <ModalHeader title="Confirm Delete" />
162	        <ModalBody>
163	          Are you sure you want to delete the resource <b>{obj.metadata.name}</b>?
164	        </ModalBody>
165	        <ModalFooter>
166	          <Button key="confirm" variant={ButtonVariant.danger} onClick={onDeleteConfirm}>
167	            Delete
168	          </Button>
169	          <Button
170	            key="cancel"
171	            variant={ButtonVariant.link}
172	            onClick={() => setIsDeleteModalOpen(false)}
173	          >
174	            Cancel
175	          </Button>
176	        </ModalFooter>
177	      </Modal>
178	    </>
179	  );
180	};
181	
182	export default DropdownWithKebab;

